parameters.text:
=Write a personalized cold SMS for this property manager.

CONTACT:
- Name: {{ $json['[\'First Name\']'] }}{{ $json['[\'Last Name\']'] }}
- Title: {{ $json['[\'Job Title\']'] }}
- Company: {{ $json['Company'] }}
- Units managed:{{ $json['[\'Door Count\']'] }} 
- PMS: {{ $json['PMS']}}
- Website: {{ $json['Domain']}}

OFFER: $500 flat. Custom AI agent built for their specific processes. Handles tenant FAQs, drafts emails, pulls reports 24/7. This is not another SaaS product, you own the tool.

STEPS:
1. Use the firecrawl tool to scrape https://{{ $json['Domain'] }} and learn about their business. Pick ONE specific detail to reference.
2. Write the SMS following all rules in your system prompt.
3. Use the format_sms tool to validate your draft.
4. If format_sms returns issues, fix them and validate again.
5. Return ONLY the final validated SMS text. Nothing else.

parameters.jsCode:
const agentOutput = $input.first().json.output || $input.first().json.text || '';

let sms = agentOutput.replace(/^["']|["']$/g, '').trim();

// Get phone from the Process One at a Time node
let phone = $('Process One at a Time').first().json.phone || $('Process One at a Time').first().json.Phone || '';
phone = phone.toString().replace(/[^0-9+]/g, '');
if (!phone.startsWith('+')) {
  if (!phone.startsWith('1')) phone = '1' + phone;
  phone = '+' + phone;
}

// Alternate phone numbers
const batchIndex = $('Process One at a Time').first().json.batchIndex || 0;
const fromNumbers = ['+1XXXXXXXXXX', '+1YYYYYYYYYY'];
const fromNumber = fromNumbers[batchIndex % 2];

return [{
  json: {
    sms_message: sms,
    mobile_phone: phone,
    from_number: fromNumber,
    chars: sms.length
  }
}];

const draft = query;

const banned = ['leverage','streamline','optimize','revolutionize','game-changer','cutting-edge','best-in-class','synergy','holistic','robust','scalable','innovative','transform','unlock','empower','elevate','amplify','drive growth','pain points','touch base','circle back','deep dive','move the needle','low-hanging fruit','at the end of the day','reach out','loop in','take it to the next level','actionable insights','value proposition','paradigm shift','no monthly fees','no ongoing fees','no recurring cost'];

let issues = [];
const lower = draft.toLowerCase();

for (const w of banned) {
  if (lower.includes(w)) issues.push('Contains banned phrase: ' + w);
}

if (draft.includes('—')) issues.push('Contains em dash');
if (draft.includes(';')) issues.push('Contains semicolon');
if (draft.includes('!')) issues.push('Contains exclamation mark');
if (draft.length > 400) issues.push('Over 400 chars: ' + draft.length);
if (draft.length > 250) issues.push('Over 250 chars preferred: ' + draft.length + '. Try to shorten.');
if (draft.startsWith('Hi ') || draft.startsWith('Hello ') || draft.startsWith('Dear ')) issues.push('Bad greeting — use Hey or just the name');
if (!draft.includes('- Jacob')) issues.push('Missing "- Jacob" sign-off');

if (issues.length > 0) {
  return 'ISSUES FOUND — fix these and try again: ' + issues.join('. ');
}

return 'SMS APPROVED (' + draft.length + ' chars)';

